namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using System.ComponentModel.DataAnnotations;

namespace RecipeHub.Models;

public class RecipeSubmission
{
    [Required(ErrorMessage = "Title is required.")]
    [StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Description is required.")]
    [StringLength(500, ErrorMessage = "Description must be 500 characters or fewer.")]
    public string Description { get; set; } = string.Empty;

    [Required(ErrorMessage = "Ingredients are required.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required(ErrorMessage = "Steps are required.")]
    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh mozzarella, tomatoes, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = [
                    "Preheat oven to 475°F (245°C) with a pizza stone inside.",
                    "Stretch the dough into a 12-inch round on a floured surface.",
                    "Spread crushed tomatoes evenly, leaving a 1-inch border.",
                    "Tear mozzarella into pieces and distribute over the sauce.",
                    "Bake for 10–12 minutes until the crust is golden and cheese is bubbly.",
                    "Top with fresh basil leaves and a drizzle of olive oil."
                ],
                TotalRatings = 12, RatingSum = 53
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy pasta with pancetta, egg, and Parmesan — no cream needed.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan cheese", "Black pepper", "Salt"],
                Steps = [
                    "Cook spaghetti in salted boiling water until al dente.",
                    "Fry pancetta in a skillet until crispy.",
                    "Whisk eggs and grated Parmesan together in a bowl.",
                    "Drain pasta, reserving 1 cup of pasta water.",
                    "Toss hot pasta with pancetta, then quickly stir in the egg mixture off heat.",
                    "Add pasta water a splash at a time to reach a silky consistency. Season with pepper."
                ],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken thighs", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cumin", "Turmeric"],
                Steps = [
                    "Marinate chicken in yogurt, garam masala, cumin, and turmeric for at least 1 hour.",
                    "Grill or broil marinated chicken until charred and cooked through.",
                    "Sauté onion, garlic, and ginger in a pan until soft.",
                    "Add tomato sauce and spices; simmer for 15 minutes.",
                    "Stir in heavy cream and the cooked chicken pieces.",
                    "Simmer for 10 minutes. Serve over basmati rice."
                ],
                TotalRatings = 15, RatingSum = 70
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Samosas", Category = "Indian",
                Description = "Crispy pastry pockets filled with spiced potatoes and peas.",
                Ingredients = ["Potatoes", "Green peas", "Cumin seeds", "Garam masala", "Flour", "Oil for frying", "Green chilies", "Cilantro"],
                Steps = [
                    "Boil and mash potatoes. Mix with peas, cumin, garam masala, and chopped chilies.",
                    "Make dough from flour, salt, and water; rest for 30 minutes.",
                    "Roll dough into circles, cut in half, and form cones.",
                    "Fill cones with the potato mixture and seal edges with water.",
                    "Deep fry at 350°F until golden brown and crispy.",
                    "Serve with mint chutney and tamarind sauce."
                ],
                TotalRatings = 6, RatingSum = 27
            },
            new Recipe
            {
                Id = 5, Title = "Tacos al Pastor", Category = "Mexican",
                Description = "Marinated pork tacos with pineapple, onion, and cilantro.",
                Ingredients = ["Pork shoulder", "Dried guajillo chiles", "Pineapple", "Corn tortillas", "Onion", "Cilantro", "Lime", "Achiote paste"],
                Steps = [
                    "Blend soaked guajillo chiles, achiote paste, and pineapple juice into a marinade.",
                    "Marinate sliced pork for at least 4 hours or overnight.",
                    "Cook pork on a hot griddle or grill until caramelized.",
                    "Grill pineapple slices until charred; dice.",
                    "Warm corn tortillas on the griddle.",
                    "Assemble tacos with pork, pineapple, diced onion, cilantro, and a squeeze of lime."
                ],
                TotalRatings = 10, RatingSum = 46
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh avocado dip with lime, cilantro, and jalapeño.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = [
                    "Halve and pit the avocados; scoop into a bowl.",
                    "Mash with a fork to desired consistency.",
                    "Stir in diced onion, tomato, jalapeño, and cilantro.",
                    "Add lime juice and salt to taste.",
                    "Serve immediately with tortilla chips."
                ],
                TotalRatings = 20, RatingSum = 90
            },
            new Recipe
            {
                Id = 7, Title = "Pad Thai", Category = "Asian",
                Description = "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.",
                Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Peanuts", "Tamarind paste", "Fish sauce", "Lime", "Green onions", "Garlic"],
                Steps = [
                    "Soak rice noodles in warm water for 30 minutes; drain.",
                    "Mix tamarind paste, fish sauce, and sugar into a sauce.",
                    "Stir-fry shrimp and garlic in a hot wok; set aside.",
                    "Scramble eggs in the wok, then add noodles and sauce.",
                    "Toss with shrimp, bean sprouts, and green onions.",
                    "Serve topped with crushed peanuts and a lime wedge."
                ],
                TotalRatings = 9, RatingSum = 41
            },
            new Recipe
            {
                Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Individual cakes with a warm, molten chocolate center.",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
                Steps = [
                    "Preheat oven to 425°F (220°C). Butter and flour four ramekins.",
                    "Melt chocolate and butter together; let cool slightly.",
                    "Whisk eggs, sugar, and vanilla until thick.",
                    "Fold in the chocolate mixture, then gently fold in flour.",
                    "Divide batter among ramekins.",
                    "Bake for 12–14 minutes until edges are set but center is soft.",
                    "Invert onto plates and serve immediately."
                ],
                TotalRatings = 18, RatingSum = 86
            },
        ];
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = submission.Description,
            Ingredients = submission.Ingredients
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = submission.Steps
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

@using RecipeHub.Services
@rendermode InteractiveServer
@inject RecipeService Recipes

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="star-btn @(star <= _hoveredStar ? "hovered" : "") @(star <= _selectedStar ? "selected" : "")"
                @onclick="() => SubmitRating(star)"
                @onmouseover="() => _hoveredStar = star"
                @onmouseout="() => _hoveredStar = 0"
                title="Rate @star star@(star > 1 ? "s" : "")"
                disabled="@_hasRated">
            ★
        </button>
    }
    <span class="rating-info">
        @if (_hasRated)
        {
            <span class="thank-you">Thanks for rating!</span>
        }
        @if (_averageRating > 0)
        {
            <span class="avg">@_averageRating.ToString("F1") / 5</span>
            <span class="count">(@_totalRatings @(_totalRatings == 1 ? "rating" : "ratings"))</span>
        }
    </span>
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    [Parameter]
    public double InitialAverage { get; set; }

    [Parameter]
    public int InitialTotal { get; set; }

    private int _hoveredStar;
    private int _selectedStar;
    private bool _hasRated;
    private double _averageRating;
    private int _totalRatings;

    protected override void OnInitialized()
    {
        _averageRating = InitialAverage;
        _totalRatings = InitialTotal;
    }

    private void SubmitRating(int stars)
    {
        if (_hasRated) return;

        _selectedStar = stars;
        Recipes.AddRating(RecipeId, stars);

        var recipe = Recipes.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            _averageRating = recipe.AverageRating;
            _totalRatings = recipe.TotalRatings;
        }

        _hasRated = true;
    }
}

