arguments.file_text:
.star-rating {
    display: flex;
    align-items: center;
    gap: 0.15rem;
    flex-wrap: wrap;
}

.star-btn {
    background: none;
    border: none;
    font-size: 1.75rem;
    color: #ccc;
    cursor: pointer;
    padding: 0;
    line-height: 1;
    transition: color 0.15s, transform 0.15s;
}

.star-btn:hover:not(:disabled),
.star-btn.hovered {
    color: #f0ad4e;
    transform: scale(1.2);
}

.star-btn.selected {
    color: #f0ad4e;
}

.star-btn:disabled {
    cursor: default;
}

.rating-info {
    margin-left: 0.75rem;
    font-size: 0.9rem;
    color: #666;
}

.thank-you {
    color: #28a745;
    font-weight: 600;
    margin-right: 0.5rem;
}

@page "/"
@using RecipeHub.Services
@inject RecipeService Recipes

<PageTitle>RecipeHub — Home</PageTitle>

<div class="hero">
    <h1>🍳 RecipeHub</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="category-grid">
    @foreach (var category in Recipes.GetCategories())
    {
        <a href="category/@category" class="category-card">
            <div class="category-icon">@GetCategoryEmoji(category)</div>
            <h3>@category</h3>
            <p>@Recipes.GetRecipesByCategory(category).Count recipe(s)</p>
        </a>
    }
</div>

@code {
    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🥢",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

@page "/category/{CategoryName}"
@using RecipeHub.Services
@inject RecipeService Recipes

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

@if (_recipes.Count == 0)
{
    <h1>Category not found</h1>
    <p>No recipes found for "@CategoryName". <a href="/">Browse all categories</a>.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1>@CategoryName Recipes</h1>

    <div class="recipe-list">
        @foreach (var recipe in _recipes)
        {
            <a href="recipe/@recipe.Id" class="recipe-card">
                <h3>@recipe.Title</h3>
                <p>@recipe.Description</p>
                <div class="recipe-meta">
                    @if (recipe.AverageRating > 0)
                    {
                        <span class="stars">★ @recipe.AverageRating.ToString("F1")</span>
                    }
                    <span class="ingredients-count">@recipe.Ingredients.Count ingredients</span>
                    <span class="steps-count">@recipe.Steps.Count steps</span>
                </div>
            </a>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<RecipeHub.Models.Recipe> _recipes = [];

    protected override void OnInitialized()
    {
        _recipes = Recipes.GetRecipesByCategory(CategoryName);
    }
}

