toolArgs.file_text:
@page "/category/{CategoryName}"
@using RecipeHub.Services
@inject RecipeService Recipes

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

@if (_recipes.Count == 0)
{
    <h1>Category not found</h1>
    <p>No recipes found for "@CategoryName". <a href="/">Browse all categories</a>.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1>@CategoryName Recipes</h1>

    <div class="recipe-list">
        @foreach (var recipe in _recipes)
        {
            <a href="recipe/@recipe.Id" class="recipe-card">
                <h3>@recipe.Title</h3>
                <p>@recipe.Description</p>
                <div class="recipe-meta">
                    @if (recipe.AverageRating > 0)
                    {
                        <span class="stars">★ @recipe.AverageRating.ToString("F1")</span>
                    }
                    <span class="ingredients-count">@recipe.Ingredients.Count ingredients</span>
                    <span class="steps-count">@recipe.Steps.Count steps</span>
                </div>
            </a>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<RecipeHub.Models.Recipe> _recipes = [];

    protected override void OnInitialized()
    {
        _recipes = Recipes.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Components.Shared
@using RecipeHub.Services
@inject RecipeService Recipes

<PageTitle>@(_recipe?.Title ?? "Recipe Not Found") — RecipeHub</PageTitle>

@if (_recipe is null)
{
    <h1>Recipe not found</h1>
    <p><a href="/">Browse all categories</a>.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <h1>@_recipe.Title</h1>
    <p class="recipe-description">@_recipe.Description</p>

    <div class="rating-section">
        <h4>Rate this recipe</h4>
        <StarRating RecipeId="@_recipe.Id"
                    InitialAverage="@_recipe.AverageRating"
                    InitialTotal="@_recipe.TotalRatings" />
    </div>

    <div class="recipe-detail-grid">
        <section class="ingredients-section">
            <h2>Ingredients</h2>
            <ul>
                @foreach (var ingredient in _recipe.Ingredients)
                {
                    <li>@ingredient</li>
                }
            </ul>
        </section>

        <section class="steps-section">
            <h2>Steps</h2>
            <ol>
                @foreach (var step in _recipe.Steps)
                {
                    <li>@step</li>
                }
            </ol>
        </section>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeHub.Models.Recipe? _recipe;

